let cfg;

try {
  const nextItems = $items('Prepare Next Attempt');

  if (nextItems && nextItems.length > 0 && nextItems[0]?.json) {
    cfg = nextItems[0].json;
  } else {
    cfg = $items('Normalize Input + Defaults')[0].json;
  }
} catch (e) {
  cfg = $items('Normalize Input + Defaults')[0].json;
}

const response = $json;
const statusCode = Number(response.statusCode || response.status || 0);
const ok = statusCode >= 200 && statusCode < 300;
let errorMessage = '';
if (!ok) {
  errorMessage = response.statusMessage || response.message || response.error?.message || `HTTP ${statusCode || 'unknown error'}`;
}
const retryable = !ok && cfg.retryableStatusCodes.includes(statusCode);
const attemptsRemaining = cfg.attempt < cfg.maxAttempts;
const shouldRetry = retryable && attemptsRemaining;
const rawDelay = Math.min(cfg.maxDelaySeconds, cfg.baseDelaySeconds * Math.pow(2, cfg.attempt - 1));
const jitterRange = rawDelay * (cfg.jitterPercent / 100);
const jitter = Math.round((Math.random() * 2 - 1) * jitterRange);
const delaySeconds = Math.max(1, Math.round(rawDelay + jitter));
return [{ json: { ...cfg, statusCode, success: ok, retryable, shouldRetry, attemptsRemaining, delaySeconds, nextAttempt: cfg.attempt + 1, errorMessage, responseBody: response.body ?? response, lastAttemptAt: new Date().toISOString() }}];

function redact(obj) {
  const blocked = ['authorization','api_key','apikey','token','password','secret','client_secret'];
  if (obj === null || obj === undefined) return obj;
  if (Array.isArray(obj)) return obj.map(redact);
  if (typeof obj === 'object') {
    return Object.fromEntries(Object.entries(obj).map(([k,v]) => {
      if (blocked.some(b => k.toLowerCase().includes(b))) return [k, '***REDACTED***'];
      return [k, redact(v)];
    }));
  }
  return obj;
}
const failure = {
  outcome: 'retry_exhausted',
  severity: 'HIGH',
  operationName: $json.operationName,
  correlationId: $json.correlationId,
  executionId: $json.executionId,
  workflowName: $json.workflowName,
  attemptsUsed: $json.attempt,
  maxAttempts: $json.maxAttempts,
  statusCode: $json.statusCode,
  errorMessage: $json.errorMessage,
  retryable: $json.retryable,
  startedAt: $json.startedAt,
  failedAt: new Date().toISOString(),
  lastResponse: redact($json.responseBody),
  input: redact({ url: $json.url, method: $json.method, headers: $json.headers, query: $json.query, body: $json.body }),
  previousAttempts: $json.previousAttempts || [],
  slackChannel: $json.slackChannel,
  notifyEmail: $json.notifyEmail
};
return [{ json: failure }];
